"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["2237"],{87915(i,e,a){a.r(e),a.d(e,{default:()=>n});var o=a(74848),t=a(47643),r=JSON.parse('{"id":70,"it":{"title":"life coach","prompt":"I want you to act as a life coach. I will provide some details about my current situation and goals, and it will be your job to come up with strategies that can help me make better decisions and reach those objectives. This could involve offering advice on various topics, such as creating plans for achieving success or dealing with difficult emotions. Respond in Italian. My first request is [situazione attuale e obiettivi]","description":"Voglio che lei agisca come life coach. Le fornir\xf2 alcuni dettagli sulla mia situazione attuale e sui miei obiettivi, e il suo compito sar\xe0 quello di elaborare strategie che mi aiutino a prendere decisioni migliori e a raggiungere tali obiettivi. Ci\xf2 pu\xf2 comportare la fornitura di consigli su una serie di argomenti, come lo sviluppo di un piano per raggiungere il successo o la gestione di emozioni difficili.","remark":"Fornire piani e raccomandazioni per raggiungere gli obiettivi sulla base delle condizioni attuali e degli obiettivi."},"tags":["social"],"website":"https://github.com/f/awesome-chatgpt-prompts#act-as-a-life-coach","count":849,"related":[{"id":251,"title":"fantasma (soprattutto nella fantasia occidentale)","remark":"\u26A0\uFE0F Prima di utilizzare questa richiesta, \xe8 necessario utilizzare il prompt per sbloccare la modalit\xe0 sviluppatore. L\'IA che interpreta il Fantasma \xe8 perfetta per la trama intima del libro. Contributo di @mrdog233o5."},{"id":199,"title":"Generatore di dialoghi eterosessuali","remark":"Continuare una conversazione basandosi su un pezzo di dialogo tra s\xe9 e l\'interlocutore, usato per prolungare la conversazione e per evitare la freddezza. Le parole del prompt devono essere modificate in base alla propria situazione. (Inserire il prompt cinese direttamente in New Bing, l\'intelligenza artificiale potrebbe non farlo, basta inserire l\'inglese e si pu\xf2 inserire il cinese in un secondo momento). Contributo di @lsdt45."},{"id":212,"title":"Esperienza di psicoterapia AI","remark":"Guidare i consulenti AI a sfruttare appieno il loro ruolo di esperti psicoterapeutici per offrirvi un\'esperienza di consulenza approfondita e completa. Contributo di @Antoine2033."}],"metaTitle":"Life Coach: Obiettivi e Successo","metaDescription":"Ti senti bloccato? Crea piani pratici per successo e benessere. Ottieni consigli esperti per raggiungere i tuoi obiettivi ora!","faq":[{"q":"I consigli del life coach sono troppo idealistici?","a":"A volte s\xec. L\'AI tende al \xabdovresti fare cos\xec\xbb, senza considerare risorse limitate. Aggiungi \xabipotizza che tempo, denaro ed energia siano al 50%, indica solo l\'azione minima sostenibile\xbb: riporta i castelli in aria al livello davvero realizzabile."},{"q":"In cosa l\'AI differisce da un coach umano?","a":"L\'AI non traccia i tuoi progressi, non ti scuote nei momenti pigri e non vede le espressioni contraddittorie. Va bene per la pianificazione iniziale e per i consigli; per obiettivi di lungo respiro (transizione di carriera, trasformazione della salute) serve un accountability partner umano: l\'AI \xe8 pi\xf9 una consulenza spot."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function n(){return(0,o.jsx)(t.A,{prompt:r,currentLanguage:"it"})}}}]);